kernel void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw, 
        float cn, float cs,
        float ct, float cb, 
        float cc) 
{
    float amb_temp = 80.0f;

    int i = get_local_id(0) + get_group_id(0) * get_local_size(0);  
    int j = get_local_id(1) + get_group_id(1) * get_local_size(1);

    int c = i + j * nx;
    int xy = nx * ny;

    int W = (0 == i)        ? c : c - 1;
    int E = (nx-1 == i)     ? c : c + 1;
    int N = (0 == j)        ? c : c - nx;
    int S = (ny-1 == j)     ? c : c + nx;

    float temp1, temp2, temp3;
    temp1 = temp2 = tIn[c];
    temp3 = tIn[c+xy];
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    c = c + (xy);
    W = W + (xy);
    E = E + (xy);
    N = N + (xy);
    S = S + (xy);

    for (int k = 1; nz-1 > k; ++k) {
        temp1 = temp2;
        temp2 = temp3;
        temp3 = tIn[c+xy];
        tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
        c = c + (xy);
        W = W + (xy);
        E = E + (xy);
        N = N + (xy);
        S = S + (xy);
    }
    temp1 = temp2;
    temp2 = temp3;
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    return;
}
